function genUserName(seed) {
  const adjectives = [
    "Swift",
    "Bright",
    "Calm",
    "Bold",
    "Wise",
    "Kind",
    "Quick",
    "Brave",
    "Cool",
    "Sharp",
    "Clear",
    "Strong",
    "Smart",
    "Fast",
    "Keen",
    "Pure",
    "Noble",
    "Gentle",
    "Fierce",
    "Steady",
    "Clever",
    "Proud",
    "Silent",
    "Wild"
  ];
  const nouns = [
    "Fox",
    "Eagle",
    "Wolf",
    "Bear",
    "Lion",
    "Tiger",
    "Hawk",
    "Owl",
    "Deer",
    "Raven",
    "Falcon",
    "Lynx",
    "Otter",
    "Whale",
    "Shark",
    "Dolphin",
    "Phoenix",
    "Dragon",
    "Panther",
    "Jaguar",
    "Cheetah",
    "Leopard",
    "Puma",
    "Cobra"
  ];
  let hash = 0;
  for (let i31 = 0; i31 < seed.length; i31++) {
    const char = seed.charCodeAt(i31);
    hash = (hash << 5) - hash + char;
    hash = hash & hash;
  }
  const adjIndex = Math.abs(hash) % adjectives.length;
  const nounIndex = Math.abs(hash >> 8) % nouns.length;
  return [adjectives[adjIndex], nouns[nounIndex]].join(" ");
}

