var CITADEL_PUBKEY = "01d077c7b21bfee89a6883edabcd408ef324e9ab431f46bf57d5860430bcb97c";
function useCitadelFeed() {
  const { nostr } = s17();
  return ce2({
    queryKey: ["citadel-feed"],
    queryFn: async () => {
      const events = await nostr.query([
        {
          kinds: [1],
          authors: [CITADEL_PUBKEY],
          limit: 50
        }
      ]);
      return events.sort((a61, b25) => b25.created_at - a61.created_at);
    },
    staleTime: 60 * 1e3,
    // 1 minute
    retry: 3
  });
}

